import {Injectable} from '@angular/core';
import {HttpClient} from '@angular/common/http';

import {CheckAuthApiResponse, Patient} from '../../interfaces/auth-interfaces';

@Injectable({
  providedIn: 'root'
})
export class AuthService {

  AUTH_API_URL = "http://localhost:8000/auth/users";

  constructor(private http: HttpClient) {

  }

  checkAuth() {
    return this.http.get<CheckAuthApiResponse>(this.AUTH_API_URL + '/check', {withCredentials: true});
  }

  getAllPatients() {
    return this.http.get<Patient[]>(this.AUTH_API_URL + '/patients', {withCredentials: true});
  }

  getUserById(id: string) {
    return this.http.get<{ name: string }>(this.AUTH_API_URL + '/name/' + id, {withCredentials: true});
  }

  signup(username: string, password: string, email: string, role: string) {
    return this.http.post(this.AUTH_API_URL + "/signup", {
      username: username,
      password: password,
      email: email,
      role: role
    }, {withCredentials: true});
  }

  login(username: string, password: string) {
    return this.http.post(this.AUTH_API_URL + "/login", {
      username: username,
      password: password
    }, {withCredentials: true});
  }

  logout() {
    return this.http.get(this.AUTH_API_URL + "/logout", {withCredentials: true});
  }
}

import { Injectable } from '@angular/core';
import {HttpClient} from '@angular/common/http';
import {ReportApiResponse} from '../../interfaces/reports-interfaces';

@Injectable({
  providedIn: 'root'
})
export class ReportsService {

  REPORTS_API_URL = "http://localhost:8000/reports";

  constructor(private http: HttpClient) {

  }

  getAllReports(){
    return this.http.get<ReportApiResponse[]>(this.REPORTS_API_URL, { withCredentials: true });
  }

  getReportById(id: string){
    return this.http.get<ReportApiResponse>(this.REPORTS_API_URL + "/" + id, { withCredentials: true });
  }

  getPatientReports(){
    return this.http.get<ReportApiResponse[]>(this.REPORTS_API_URL + "/patient", { withCredentials: true });
  }

  addReport(id_doctor: string, id_patient: string, text: string) {
    return this.http.post(this.REPORTS_API_URL, {id_doctor, id_patient, text}, {withCredentials: true});
  }

  editReport(id: string, id_doctor: string, id_patient: string, text: string) {
    return this.http.put(this.REPORTS_API_URL + "/" + id, {id_doctor, id_patient, text}, {withCredentials: true});
  }

  deleteReport(id: string) {
    return this.http.delete(this.REPORTS_API_URL + "/" + id, {withCredentials: true});
  }
}

